import React, { createContext, useState, useEffect } from 'react';
import api from '../services/api';

export const CandidateContext = createContext();

export const CandidateProvider = ({ children }) => {
  const [candidates, setCandidates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchCandidates = async () => {
    setLoading(true);
    try {
      const res = await api.getCandidates();
      setCandidates(res.data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const addCandidate = async (candidateData) => {
    await api.createCandidate(candidateData);
    fetchCandidates();
  };

  const updateCandidate = async (id, candidateData) => {
    await api.updateCandidate(id, candidateData);
    fetchCandidates();
  };

  const deleteCandidate = async (id) => {
    await api.deleteCandidate(id);
    fetchCandidates();
  };

  useEffect(() => {
    fetchCandidates();
  }, []);

  return (
    <CandidateContext.Provider value={{ candidates, loading, error, addCandidate, updateCandidate, deleteCandidate }}>
      {children}
    </CandidateContext.Provider>
  );
};
